var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"PITER_BORDER_NULL_ARMED","text":{"KOREA":"정말… 이래도 괜찮은 걸까요?","JPN":"本当に……これでいいんでしょうか？","ENG":"Will this... really work?","TWN":"這樣…真的沒關係嗎？"},"stage":{"bg":"HOSPITAL","slots":{"L":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PITER_BORDER_NULL_ARMED","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"떨지 마라. 지금 이걸 할 수 있는 사람은 귀관뿐이다.","JPN":"震えるな。今これができるのは貴官だけだ。","ENG":"Stop shaking. You're the only person who can do this right now.","TWN":"別緊張，現在只有你能做這件事。"},"stage":{"bg":"HOSPITAL","slots":{"L":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PITER_BORDER_NULL_ARMED","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"PITER_BORDER_NULL_ARMED","text":{"KOREA":"네……. 그럼 어디 한 번 해 보자고요.","JPN":"はい……じゃあ、やってみます。","ENG":"Okay.... Then let's see what'll happen.","TWN":"嗯……那我試試看吧。"},"stage":{"bg":"HOSPITAL","slots":{"L":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PITER_BORDER_NULL_ARMED","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"PITER_BORDER_NULL_ARMED","text":{"KOREA":"실례하겠습니다, 지휘관님.","JPN":"失礼します、指揮官。","ENG":"Excuse me, Sir.","TWN":"抱歉囉，指揮官。"},"stage":{"bg":"HOSPITAL","slots":{"L":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PITER_BORDER_NULL_ARMED","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"난 지금부터 그림자를 쫓아가서 시간을 끌 거야.","JPN":"私は今からシャドウを追いかけて時間を稼ぐ。","ENG":"I'll go after the Shadow and buy us some time.","TWN":"現在起我會追著暗影拖延時間。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"피터, 너는 장교님을 도와서 절개 수술을 진행하도록 해.","JPN":"ピーター、あなたは将校を手伝って切開手術をするように。","ENG":"Peter, you go perform the surgery with Officer Rashford's help.","TWN":"彼得，你來協助軍官進行手術。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"PITER_BORDER_NULL_ARMED","text":{"KOREA":"저, 절개 수술이라고요?! 제가요?!","JPN":"せ、切開手術！？　僕がですか！？","ENG":"S-surgery?! ME?!!","TWN":"手…手術？！我嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"PITER_BORDER_NULL_ARMED","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"그래. 오랫동안 내 조수를 맡아 온 너라면 할 수 있어.","JPN":"そう。長い間私の助手をしていたあなたならできる。","ENG":"You've been assisting me for years. I know you'll be able to do it.","TWN":"沒錯，你不是一直擔任我的助手嗎？你可以的。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"PITER_BORDER_NULL_ARMED","text":{"KOREA":"엘라 대장님을 의심하는 건 아니지만……","JPN":"エラ隊長を疑ってるわけじゃないですけど……","ENG":"It's not that I'm questioning your judgment, Captain Ella, but...","TWN":"我不是在質疑艾拉隊長……"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"PITER_BORDER_NULL_ARMED","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"PITER_BORDER_NULL_ARMED","text":{"KOREA":"수술을 해서 아무 일도 일어나지 않으면 어쩌죠?","JPN":"手術をしても何も起こらなかったらとどうするんですか？","ENG":"What if nothing happens after we're done?","TWN":"但萬一手術後，什麼事都沒有發生怎麼辦？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"PITER_BORDER_NULL_ARMED","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"지휘관이 왔을 때를 기억해?","JPN":"指揮官が来た時のこと、覚えているか？","ENG":"Do you remember the day Commander came here?","TWN":"你還記得指揮官來的時候嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"PITER_BORDER_NULL_ARMED","text":{"KOREA":"네…? 그야 물론이죠.","JPN":"え……？　それはもちろんです。","ENG":"Hmm...? Well, of course I do!","TWN":"嗯……？當然記得。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"PITER_BORDER_NULL_ARMED","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"그때 우리가 수술실에서 지휘관을 어떻게 치료했지?","JPN":"あの時、私たちは手術室で指揮官をどう治療した？","ENG":"Do you remember what we saw while treating him that day?","TWN":"當時我們在手術室怎麼治療指揮官的？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"PITER_BORDER_NULL_ARMED","text":{"KOREA":"가슴 한가운데에…… 무기가 박혀 있었죠.","JPN":"胸の真ん中に……武器が刺さってましたね。","ENG":"There was... a weapon lodged in the middle of his chest.","TWN":"在胸口中間…… 嵌入武器。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"PITER_BORDER_NULL_ARMED","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"PITER_BORDER_NULL_ARMED","text":{"KOREA":"신경과 거의 맞닿았던 데다가, 지휘관님 상태가 안 좋아서 그대로 뽑으면 출혈을 못 버티고 죽을 것 같았어요.","JPN":"神経と隣接してるし、指揮官の状態が悪かったので、そのまま抜くと出血に耐えられずに死ぬかもしれませんでした。","ENG":"It was touching up against his nerves, and his condition was pretty bad. So we figured we'd kill him if we tried to get it out.","TWN":"因爲幾乎都連接著神經，再加上指揮官的狀態不好，如果直接拔掉的話，感覺會出血過多而死。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"무기가 박혀 있었다고……? 그럼 그건 어떻게 했나?","JPN":"武器が刺さっていただって……？　それでは、その武器はどうしたんだ？","ENG":"There was a weapon in his chest...? Then what did you do with it?","TWN":"嵌入武器…？ 你是怎麼做到的？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"돌출부만 제거하고 경과를 관찰해 왔습니다. 다행히 거부반응은 나타나지 않더군요.","JPN":"突き出ている部分だけを除去して、経過を観察してきました。幸い、拒絶反応は起きませんでした。","ENG":"We removed the parts that were sticking out and looked over his recovery. Luckily, there were no signs of rejection.","TWN":"我只有取出突起的部分，接著就一直觀察，幸好沒有出現排斥反應。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};